def create_upstream():
    upstream_data = {
        "name": SERVICE_NAME
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams', json=upstream_data)
    return response.json()

def create_target(upstream_id):
    target_data = {
        "target": "my_target_service:80",
        "weight": 100
    }
    response = requests.post(f'{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets', json=target_data)
    return response.json()

def main():
    # Create upstream
    upstream = create_upstream()
    upstream_id = upstream['id']
    
    # Create service
    service = create_service()
    service_id = service['id']
    
